use std::collections::BinaryHeap;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let mut adj = vec![vec![]; n as usize];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let start = edge[2];
        let end = edge[3];
        adj[u].push((v, start, end));
    }

    let mut dist = vec![i64::MAX; n as usize];
    dist[0] = 0;

    let mut heap = BinaryHeap::new();
    heap.push((0, 0));

    while let Some((current_time, u)) = heap.pop() {
        if u == (n - 1) as usize {
            return current_time;
        }
        if current_time > dist[u] {
            continue;
        }
        for (v, start, end) in &adj[u] {
            let s = std::cmp::max(current_time, *start);
            if s > *end {
                continue;
            }
            let next_time = s + 1;
            if next_time < dist[*v] {
                dist[*v] = next_time;
                heap.push((next_time, *v));
            }
        }
    }

    -1
}
